pub fn clickhouse_config_from_database_url(database_url: &str) -> CarbonResult<ClickHouseConfig> {
    ClickHouseConfig::from_database_url(
        database_url,
        DEFAULT_DATABASE.to_string(),
        JupiterSwapClaimInstructionLandingRow::DEFAULT_TABLE_NAME.to_string(),
        DEFAULT_SOURCE_NAME.to_string(),
        DEFAULT_MODE.to_string(),
        DEFAULT_DECODER_VERSION.to_string(),
        DEFAULT_MAX_ROWS,
        Duration::from_millis(DEFAULT_FLUSH_INTERVAL_MS),
    )
}

pub async fn bootstrap_clickhouse_from_database_url(
    database_url: &str,
) -> CarbonResult<ClickHouseConfig> {
    let config = clickhouse_config_from_database_url(database_url)?;
    JupiterSwapClickHouseInstructionsMigration::run(&config).await?;
    Ok(config)
}

pub fn clickhouse_processor(config: ClickHouseConfig) -> JupiterSwapClickHouseInstructionProcessor {
    ClickHouseInstructionProcessor::new(config)
}

pub async fn setup_clickhouse(
    database_url: &str,
) -> CarbonResult<JupiterSwapClickHouseInstructionProcessor> {
    let config = bootstrap_clickhouse_from_database_url(database_url).await?;
    Ok(clickhouse_processor(config))
}

#[cfg(test)]
mod tests {
    use super::*;
    use carbon_core::transaction::TransactionMetadata;
    use solana_hash::Hash;
    use solana_message::VersionedMessage;
    use solana_signature::Signature;
    use solana_transaction_status::TransactionStatusMeta;
    use std::{sync::Arc, time::Duration};

    fn metadata(block_time: Option<i64>) -> InstructionMetadata {
        let transaction_metadata = TransactionMetadata {
            slot: 55,
            signature: Signature::new_unique(),
            fee_payer: solana_pubkey::Pubkey::new_unique(),
            meta: TransactionStatusMeta::default(),
            message: VersionedMessage::Legacy(solana_message::legacy::Message::default()),
            index: Some(11),
            block_time,
            block_hash: Some(Hash::new_unique()),
        };

        InstructionMetadata {
            transaction_metadata: Arc::new(transaction_metadata),
            stack_height: 2,
            index: 3,
            absolute_path: vec![1, 2],
        }
    }

    fn context() -> ClickHouseRowContext {
        ClickHouseRowContext {
            source_name: "block_crawler".to_string(),
            mode: "backfill".to_string(),
            decoder_version: "v1".to_string(),
        }
    }

    fn config() -> ClickHouseConfig {
        ClickHouseConfig::new(
            "http://localhost:8123".to_string(),
            "default".to_string(),
            None,
            None,
            JupiterSwapClaimInstructionLandingRow::DEFAULT_TABLE_NAME.to_string(),
            "source".to_string(),
            "live".to_string(),
            "v1".to_string(),
            100,
            Duration::from_secs(60),
        )
    }

    #[test]
    fn migration_operations_include_all_instruction_and_event_tables() {
        let operations = JupiterSwapClickHouseInstructionsMigration::operations(&config());

        assert_eq!(operations.len(), 23);
        assert!(operations
            .iter()
            .any(|sql| sql.contains(JupiterSwapRouteInstructionLandingRow::DEFAULT_TABLE_NAME)));
        assert!(operations
            .iter()
            .any(|sql| sql.contains(JupiterSwapSwapEventLandingRow::DEFAULT_TABLE_NAME)));
        assert!(operations.iter().any(|sql| sql
            .contains(JupiterSwapBestSwapOutAmountViolationEventLandingRow::DEFAULT_TABLE_NAME)));
    }

    #[test]
    fn wrapper_emits_typed_cpi_event_row() {
        let swap_event = crate::events::swap_event::SwapEventEvent {
            amm: solana_pubkey::Pubkey::new_unique(),
            input_mint: solana_pubkey::Pubkey::new_unique(),
            input_amount: 12,
            output_mint: solana_pubkey::Pubkey::new_unique(),
            output_amount: 34,
        };
        let wrapper = JupiterSwapInstructionWithClickHouseMetadata(
            JupiterSwapInstruction::CpiEvent {
                program_id: crate::PROGRAM_ID,
                data: super::super::CpiEvent::SwapEvent(swap_event),
                accounts: super::super::CpiEventInstructionAccounts {
                    program: crate::PROGRAM_ID,
                    event_authority: solana_pubkey::Pubkey::new_unique(),
                    remaining: Vec::new(),
                },
            },
            metadata(Some(1_704_067_200)),
            Vec::new(),
        );

        let rows = wrapper.clickhouse_rows(&context());

        assert_eq!(rows.len(), 1);
        assert_eq!(
            rows[0].table_name(),
            JupiterSwapSwapEventLandingRow::DEFAULT_TABLE_NAME
        );
    }
}
